import{_ as o,c as t,e as n,d as r,o as s,g as a}from"./app.1c033fc5.js";var i="/assets/floor.01776921.png";const S='{"title":"TechShop, USA","description":"","frontmatter":{"title":"TechShop, USA","date":"2014-10-31","cover":"techshop.jpg","youtube":"http://www.youtube.com/watch?v=ls9xwt6F3mo"},"headers":[{"level":3,"title":"8 \u0444\u0438\u043B\u0438\u0430\u043B\u043E\u0432 \u043F\u043E \u0432\u0441\u0435\u0439 \u0441\u0442\u0440\u0430\u043D\u0435","slug":"_8-\u0444\u0438n\u0438\u0430n\u043E\u0432-\u043F\u043E-\u0432\u0441\u0435\u0439-\u0441\u0442\u0440\u0430\u043D\u0435"}],"relativePath":"theory/research/techshop-usa/index.md"}',l={},p=r('<p><a href="http://www.techshop.ws" class="external-link" target="_blank" rel="noopener noreferrer">www.techshop.ws</a></p><p>\u0410\u043C\u0435\u0440\u0438\u043A\u0430\u043D\u0441\u043A\u0438\u0439 \u043F\u0438\u043E\u043D\u0435\u0440 \u0432 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445, \u043F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u0445 \u0434\u043E\u0441\u0442\u0443\u043F \u043A \u0448\u0438\u0440\u043E\u043A\u043E\u043C\u0443 \u0441\u043F\u0435\u043A\u0442\u0440\u0443 \u043A\u043E\u043C\u043F\u044C\u044E\u0442\u0435\u0440\u0438\u0437\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0437\u0430 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0443\u044E \u0430\u0431\u043E\u043D\u0435\u043D\u0442\u0441\u043A\u0443\u044E \u043F\u043B\u0430\u0442\u0443.</p><blockquote><p>Get access to over $1 million dollars worth of advanced machines and tools, sophisticated 2D and 3D design software, and other professional equipment for a very low monthly membership fee.</p></blockquote><p><img src="'+i+'" alt=""></p><h3 id="_8-\u0444\u0438n\u0438\u0430n\u043E\u0432-\u043F\u043E-\u0432\u0441\u0435\u0439-\u0441\u0442\u0440\u0430\u043D\u0435" tabindex="-1">8 \u0444\u0438\u043B\u0438\u0430\u043B\u043E\u0432 \u043F\u043E \u0432\u0441\u0435\u0439 \u0441\u0442\u0440\u0430\u043D\u0435 <a class="header-anchor" href="#_8-\u0444\u0438n\u0438\u0430n\u043E\u0432-\u043F\u043E-\u0432\u0441\u0435\u0439-\u0441\u0442\u0440\u0430\u043D\u0435" aria-hidden="true">#</a></h3><ul><li>TechShop Mid Peninsula (temporarily located in San Carlos, CA)</li><li>TechShop San Francisco (San Francisco, CA)</li><li>TechShop San Jose (San Jose, CA)</li><li>TechShop Detroit (Allen Park, MI)</li><li>TechShop Austin-Round Rock (Round Rock, TX)</li><li>TechShop Pittsburgh (Pittsburgh, PA)</li><li>TechShop Chandler (Chandler, AZ)</li><li>TechShop DC-Arlington (Arlington, VA)</li><li>TechShop St. Louis <em>In Planning</em></li><li>TechShop Los Angeles <em>In Planning</em></li></ul><p>\u041D\u0430 \u043A\u043E\u043D\u0435\u0446 2014 \u0433\u043E\u0434\u0430 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u0447\u043B\u0435\u043D\u0441\u0442\u0432\u043E \u0432 \u043A\u043E\u043C\u043F\u0430\u043D\u0438\u0438, \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u044E\u0449\u0435\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u044C \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439 \u0434\u043E\u0441\u0442\u0443\u043F \u043A \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044E \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043C, \u0440\u0430\u0431\u043E\u0447\u0438\u043C \u0441\u0442\u0430\u043D\u0446\u0438\u044F\u043C \u0434\u043B\u044F \u0434\u0438\u0437\u0430\u0439\u043D\u0430 \u0438 \u0440\u0430\u0431\u043E\u0442\u044B \u0441\u043E \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u043C\u0438 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u0430\u043C\u0438 \u043B\u044E\u0431\u043E\u0433\u043E \u0438\u0437 \u0444\u0438\u043B\u0438\u0430\u043B\u043E\u0432 TechShop \u043E\u0431\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 $120 \u2014 $175 \xA0\u0432 \u043C\u0435\u0441\u044F\u0446 \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u0441\u0440\u043E\u043A\u0430 \u043E\u043F\u043B\u0430\u0442\u044B (1 \u043C\u0435\u0441\u044F\u0446, \u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0430 \u0438\u043B\u0438 \u0433\u043E\u0442\u043E\u0432\u043E\u0439 \u0430\u0431\u043E\u043D\u0435\u043C\u0435\u043D\u0442). \u041F\u043B\u044E\u0441 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u044B \u0441\u043A\u0438\u0434\u043E\u043A \u0434\u043B\u044F \u0447\u043B\u0435\u043D\u043E\u0432 \u0441\u0435\u043C\u044C\u0438 \u0438 \u0434\u043B\u044F \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432 \u0438 \u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u043A\u043E\u0432 \u0432\u043E\u0435\u043D\u043D\u043E\u0439 \u0441\u0444\u0435\u0440\u044B.</p><p>\u0418 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0430\u044F \u0432\u044B\u0434\u0435\u0440\u0436\u043A\u0430 \u0438\u0437 \u0440\u0430\u0437\u0434\u0435\u043B\u0430 FAQ \u0441 \u0441\u0430\u0439\u0442\u0430 <a href="http://techshop.ws" class="external-link" target="_blank" rel="noopener noreferrer">techshop.ws</a>:</p><p><strong>\u0412:</strong> \u041A\u0430\u043A\u043E\u0432\u044B \u0447\u0430\u0441\u044B \u0440\u0430\u0431\u043E\u0442\u044B \u0422\u044D\u043A\u0448\u043E\u043F\u0430? <strong>\u041E:</strong> \u0422\u044D\u043A\u0448\u043E\u043F \u043E\u0442\u043A\u0440\u044B\u0442 \u0441 9 \u0443\u0442\u0440\u0430 \u0434\u043E 12 \u043D\u043E\u0447\u0438 \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C \u043A\u0440\u043E\u043C\u0435 \u043F\u0440\u0430\u0437\u0434\u043D\u0438\u0447\u043D\u044B\u0445.</p><p><strong>\u0412:</strong> \u0412\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C, \u043A\u0430\u043A \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435\u043C \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438? <strong>\u041E:</strong> \u0414\u0430! \u041C\u044B \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u043C \u043F\u0440\u043E\u0439\u0442\u0438 \u043A\u043B\u0430\u0441\u0441\u044B \u043F\u043E\xA0\u0431\u0430\u0437\u043E\u0432\u043E\u043C\u0443 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u043C\u0443 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044E (SBU) \u0447\u0442\u043E\u0431\u044B \u0431\u044B\u0441\u0442\u0440\u043E \u0438 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E \u0432\u0432\u0435\u0441\u0442\u0438 \u0432\u0430\u0441 \u0432 \u043A\u0443\u0440\u0441 \u0434\u0435\u043B\u0430.</p><p><strong>\u0412:</strong> \u041A\u0430\u043A\u0438\u0435 \u0432\u0438\u0434\u044B \u043A\u043B\u0430\u0441\u0441\u043E\u0432 \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u0442 \u0422\u044D\u043A\u0448\u043E\u043F? <strong>\u041E:</strong> \u041C\u044B \u043F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u043C \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0432\u0438\u0434\u043E\u0432 \u043A\u043B\u0430\u0441\u0441\u043E\u0432: - \u041A\u043B\u0430\u0441\u0441\u044B \u043F\u043E \u0431\u0430\u0437\u043E\u0432\u043E\u043C\u0443 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u043C\u0443 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044E \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u044B \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u043D\u0430\u0432\u044B\u043A\u0438 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0433\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u0442\u0435\u0445 \u0438\u043B\u0438 \u0438\u043D\u044B\u0445 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438\u043B\u0438 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F, - \u041F\u0443\u0442\u0435\u0432\u044B\u0435 \u043A\u043B\u0430\u0441\u0441\u044B \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u044E\u0442\u0441\u044F \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0441\u0442\u0440\u043E\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u0431\u043B\u043E\u043A\u043E\u0432, \u0441\u043F\u043E\u0441\u043E\u0431\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043F\u0440\u043E\u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044E \u0432\u0430\u0448\u0438\u0445 \u043F\u0440\u043E\u0435\u043A\u0442\u043E\u0432 \u043A \u043F\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u043C \u0446\u0435\u043B\u044F\u043C - \u041F\u0440\u043E\u0435\u043A\u0442\u043D\u044B\u0435 \u043A\u043B\u0430\u0441\u0441\u044B \u0434\u0430\u044E\u0442 \u0447\u0435\u0442\u043A\u0438\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0438 \u043F\u043E \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0442\u0435\u0445\u043D\u0438\u043A\u0430\u043C \u0438 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u044F\u043C, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u043C \u0434\u043B\u044F \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044F \u0432\u0430\u0448\u0435\u0433\u043E \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0435\u043A\u0442\u0430.</p><p><strong>\u0412:</strong> \u0414\u043E\u043B\u0436\u0435\u043D \u043B\u0438 \u044F \u0431\u044B\u0442\u044C \u0447\u043B\u0435\u043D\u043E\u043C \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u0441\u0435\u0449\u0430\u0442\u044C \u043A\u043B\u0430\u0441\u0441\u044B? <strong>\u041E:</strong> \u041D\u0435\u0442! \u041A\u0430\u0436\u0434\u044B\u0439 \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0438\u0439\u0442\u0438 \u043D\u0430 \u043E\u0431\u0443\u0447\u0430\u044E\u0449\u0438\u0435 \u043A\u043B\u0430\u0441\u0441\u044B \u0432 \u0422\u044D\u043A\u0448\u043E\u043F. (\u0415\u0441\u0442\u044C \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u043F\u043E \u0432\u043E\u0437\u0440\u0430\u0441\u0442\u0443 \u0432 \u0446\u0435\u043B\u044F\u0445 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438)</p><p><strong>\u0412:</strong> \u041A\u0430\u043A\u0438\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0438 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0422\u044D\u043A\u0448\u043E\u043F?<strong>\u041E:</strong> <em>\u0411\u0435\u0437 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430:</em></p><blockquote><p>We provide our members access to just about every machine, tool and process that you can imagine, including milling machines and lathes, Epilog laser cutters, sheet metal equipment, welding equipment, an indoor automotive work bay, woodworking equipment including a 4&#39; x 8&#39; CNC ShopBot router, plastics working equipment, hand tools, a 3D printer, computer-controlled vinyl cutter, sewing machines, design software and lots more.</p></blockquote><p><strong>\u0412:</strong> \u042F \u043C\u043E\u0433\u0443 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043B\u044E\u0431\u044B\u043C\u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438 \u0438 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0438 \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439? <strong>\u041E:</strong> \u0414\u0430, \u0435\u0441\u043B\u0438 \u0432\u044B \u043F\u0440\u043E\u0448\u043B\u0438 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u043F\u043E \u0431\u0430\u0437\u043E\u0432\u043E\u043C\u0443 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u043C\u0443 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044E \u0438\u043C\u0438, \u0435\u0441\u043B\u0438 \u044D\u0442\u043E \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u044B\u0439 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442. \u0411\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043C\u0430\u0448\u0438\u043D\u044B \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u044E\u0442 \u043F\u0440\u043E\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0442\u0430\u043A\u0438\u0445 \u043A\u043B\u0430\u0441\u0441\u043E\u0432. \u0414\u043B\u044F \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0435\u043D\u0438\u044F \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438, \u043C\u044B \u0432\u0441\u0435-\u0442\u0430\u043A\u0438 \u0442\u0440\u0435\u0431\u0443\u0435\u043C \u043F\u0440\u043E\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0431\u0430\u0437\u043E\u0432\u043E\u0433\u043E \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F \u0434\u043B\u044F \u0440\u0430\u0431\u043E\u0442\u044B \u0441 \u043B\u044E\u0431\u044B\u043C \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435\u043C, \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B\u043C \u043D\u0430\u043D\u0435\u0441\u0442\u0438 \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u044B\u0435 \u0442\u0440\u0430\u0432\u043C\u044B.</p><p><strong>\u0412:</strong> \u041C\u043E\u0433\u0443 \u044F \u0437\u0430\u0431\u0440\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0432\u0440\u0435\u043C\u044F \u0440\u0430\u0431\u043E\u0442\u044B \u043D\u0430 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0438? <strong>\u041E:</strong> \u0414\u0430! \u041F\u0440\u0438 \u043D\u0430\u043B\u0438\u0447\u0438\u0438 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0447\u043B\u0435\u043D\u0441\u0442\u0432\u0430 \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0437\u0430\u0431\u0440\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0432\u0440\u0435\u043C\u044F \u043D\u0430 \u043B\u044E\u0431\u043E\u043C \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0438 \u0434\u043E \u0441\u0432\u043E\u0435\u0433\u043E \u043F\u0440\u0438\u0445\u043E\u0434\u0430, \u043F\u043E\u0437\u0432\u043E\u043D\u0438\u0432 \u0432 \u043F\u0440\u0438\u0435\u043C\u043D\u0443\u044E \u0422\u044D\u043A\u0448\u043E\u043F\u0430.</p>',16);function c(h,g,d,u,m,_){const e=a;return s(),t("div",null,[p,n(e,{link:"http://www.youtube.com/watch?v=hHAzPIsYj8M"})])}var T=o(l,[["render",c]]);export{S as __pageData,T as default};
